#include <bits/stdc++.h>
using namespace std;

const int INF = 1e9;
int N, M;
vector<string> grid;

int di[4] = {-1, 1, 0, 0};
int dj[4] = {0, 0, -1, 1};

void dfs(int i, int j, int id, vector<vector<int>>& comp) {
    comp[i][j] = id;
    for (int d = 0; d < 4; d++) {
        int ni = i + di[d];
        int nj = j + dj[d];
        if (ni >= 0 && ni < N && nj >= 0 && nj < M && grid[ni][nj] == 'X' && comp[ni][nj] == 0) {
            dfs(ni, nj, id, comp);
        }
    }
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> N >> M;
    grid.resize(N);
    for (int i = 0; i < N; i++) {
        cin >> grid[i];
    }

    // identify the 3 components
    vector<vector<int>> comp(N, vector<int>(M, 0));
    int cur_id = 0;
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            if (grid[i][j] == 'X' && comp[i][j] == 0) {
                cur_id++;
                dfs(i, j, cur_id, comp);
            }
        }
    }

    // For each cell, compute distance to each component
    // dist[id][i][j] = min steps (Manhattan-like on grid) to reach component id from (i,j)
    vector<vector<vector<int>>> dist(4, vector<vector<int>>(N, vector<int>(M, INF)));

    for (int id = 1; id <= 3; id++) {
        queue<pair<int,int>> q;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (comp[i][j] == id) {
                    dist[id][i][j] = 0;
                    q.push({i, j});
                }
            }
        }
        // BFS on the whole grid (moving through '.' costs 1, through 'X' of same component costs 0,
        // but since we start from all X of component, we can treat moving through empty cells as cost 1)
        // Actually we want shortest path in terms of number of '.' cells we need to paint.
        // Edge: stepping into an empty cell adds 1 to the cost. Stepping into an 'X' cell (any component) adds 0.
        // So we can use 0-1 BFS or Dijkstra. Since costs are 0 or 1, 0-1 BFS.
        // But the grid is small, we can also use plain BFS with a deque.
        deque<pair<int,int>> dq;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (comp[i][j] == id) {
                    dist[id][i][j] = 0;
                    dq.push_back({i, j});
                }
            }
        }
        while (!dq.empty()) {
            auto [i, j] = dq.front(); dq.pop_front();
            for (int d = 0; d < 4; d++) {
                int ni = i + di[d];
                int nj = j + dj[d];
                if (ni < 0 || ni >= N || nj < 0 || nj >= M) continue;
                int cost = (grid[ni][nj] == '.') ? 1 : 0;
                if (dist[id][ni][nj] > dist[id][i][j] + cost) {
                    dist[id][ni][nj] = dist[id][i][j] + cost;
                    if (cost == 0) dq.push_front({ni, nj});
                    else dq.push_back({ni, nj});
                }
            }
        }
    }

    int answer = INF;

    // We need to connect all 3 components.
    // The optimal connection is either:
