    // Compute answer with one meeting point
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < M; j++) {
            int total = dist[1][i][j] + dist[2][i][j] + dist[3][i][j];
            answer = min(answer, total);
        }
    }

    // Compute answer with two meeting points (chain: a - b - c)
    // For each component b (middle), precompute for each cell the cost dist[b][cell].
